import ast
import sys

# 检查 Agent.__init__ 中是否所有属性都被初始化
with open('src/agent.py', 'r') as f:
    tree = ast.parse(f.read())

for node in ast.walk(tree):
    if isinstance(node, ast.ClassDef) and node.name == 'Agent':
        for item in node.body:
            if isinstance(item, ast.FunctionDef) and item.name == '__init__':
                # 统计 self.xxx = 的数量
                assigns = [n for n in ast.walk(item) if isinstance(n, ast.Assign)]
                attr_assigns = []
                for assign in assigns:
                    for target in assign.targets:
                        if isinstance(target, ast.Attribute) and isinstance(target.value, ast.Name) and target.value.id == 'self':
                            attr_assigns.append(target.attr)
                print(f'Agent.__init__ 初始化了 {len(attr_assigns)} 个属性')
                print('属性列表（前 20 个）:', attr_assigns[:20])
